@method_decorator(csrf_exempt, name='dispatch')
class SAMLACSView(View):
    """
    Assertion Consumer Service (ACS) endpoint.
    Handles SAML POST responses from the Identity Provider.
    """

    def post(self, request):
        saml_response = request.POST.get('SAMLResponse')
        relay_state = request.POST.get('RelayState', '')

        if not saml_response:
            return HttpResponseBadRequest(
                'Missing SAMLResponse parameter', content_type='text/plain'
            )

        try:
            # Parse and validate the SAML response
            parser = SAMLResponseParser(saml_response)
            parser.process()

            # Check for replay attacks
            response_id = parser.root.get('ID')
            if response_id:
                SAMLReplayCache.check_and_store(response_id)

            # Get or create the Django user
            user_manager = SAMLUserManager(parser)
            user = user_manager.get_or_create_user()

            # Create Django session
            login(request, user, backend='django.contrib.auth.backends.ModelBackend')

            # Store SAML-specific session data
            request.session['saml_name_id'] = parser.name_id
            request.session['saml_session_index'] = parser.session_index
            request.session['saml_attributes'] = parser.attributes
            request.session['saml_authenticated'] = True

            # Determine redirect URL
            redirect_url = relay_state or getattr(
                settings, 'SAML_LOGIN_REDIRECT_URL', '/'
            )

            # Validate redirect URL to prevent open redirect
            if not redirect_url.startswith('/'):
                redirect_url = getattr(settings, 'SAML_LOGIN_REDIRECT_URL', '/')

            return HttpResponseRedirect(redirect_url)

        except SAMLValidationError as e:
            return HttpResponseBadRequest(
                f'SAML Validation Error: {e}', content_type='text/plain'
            )
        except Exception as e:
            return HttpResponseBadRequest(
                f'SAML Processing Error: {e}', content_type='text/plain'
            )


class SAMLLoginView(View):
    """
    Initiates SAML authentication by redirecting to the IdP.
    Generates a SAML AuthnRequest.
    """

    def get(self, request):
        idp_sso_url = getattr(settings, 'SAML_IDP_SSO_URL', None)
        if not idp_sso_url:
            return HttpResponseBadRequest(
                'SAML IdP SSO URL not configured', content_type='text/plain'
            )

        sp_entity_id = getattr(settings, 'SAML_SP_ENTITY_ID', '')
        acs_url = getattr(settings, 'SAML_SP_ACS_URL', '')
        request_id = f'_id-{secrets.token_hex(16)}'
        issue_instant = datetime.now(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')

        authn_request = f'''<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{idp_sso_url}"
    AssertionConsumerServiceURL="{acs_url}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{sp_entity_id}</saml:Issuer>
    <samlp:NameIDPolicy
        Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
        AllowCreate="true"/>
</samlp:AuthnRequest>'''

        encoded_request = base64.b64encode(
            authn_request.encode('utf-8')
        ).decode('utf-8')

        relay_state = request.GET.get('next', '/')

        # Return an auto-submitting form for POST binding
        html = f'''<!DOCTYPE html>
<html>
<head><title>Redirecting to Identity Provider...</title></head>
<body onload="document.forms[0].submit();">
    <noscript>
        <p>JavaScript is required. Click the button below to continue.</p>
    </noscript>
    <form method="POST" action="{idp_sso_url}">
        <input type="hidden" name="SAMLRequest" value="{encoded_request}" />
        <input type="hidden" name="RelayState" value="{relay_state}" />
        <noscript>
            <input type="submit" value="Continue to Identity Provider" />
        </noscript>
    </form>
</body>
</html>'''

        return HttpResponse(html, content_type='text/html')


class SAMLLogoutView(View):
    """Handles SAML logout by clearing the Django session."""

    def get(self, request):
        logout(request)
        redirect_url = getattr(settings, 'SAML_LOGOUT_REDIRECT_URL', '/')
        return HttpResponseRedirect(redirect_url)

    def post(self, request):
        return self.get(request)


class SAMLMetadataView(View):
    """
    Serves the SP metadata XML for IdP configuration.
    """

    def get(self, request):
        sp_entity_id = getattr(settings, 'SAML_SP_ENTITY_ID', '')
        acs_url = getattr(settings, 'SAML_SP_ACS_URL', '')

        metadata = f'''<?xml version="1.0" encoding="UTF-8"?>
<md:EntityDescriptor
    xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
    entityID="{sp_entity_id}">
    <md:SPSSODescriptor
        AuthnRequestsSigned="false"
        WantAssertionsSigned="true"
        protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        <md:NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress</md:NameIDFormat>
        <md:AssertionConsumerService
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{acs_url}"
            index="0"
            isDefault="true"/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>'''

        return HttpResponse(metadata, content_type='application/xml')


# --- URL Configuration ---

urlpatterns = [
    path('saml/login/', SAMLLoginView.as_view(), name='saml_login'),
    path('saml/acs/', SAMLACSView.as_view(), name='saml_acs'),
    path('saml/logout/', SAMLLogoutView.as_view(), name='saml_logout'),
    path('saml/metadata/', SAMLMetadataView.as_view(), name='saml_metadata'),
]


# --- Django Middleware for SAML Session Validation ---

class SAMLSessionMiddleware:
    """
    Middleware to validate SAML session state on each request.
    Ensures the user's SAML session hasn't expired.
    """

    def __init__(self, get_response):
        self.get_response = get_response

    def __call__(self, request):
        if (
            hasattr(request, 'user')
            and request.user.is_authenticated
            and request.session.get('saml_authenticated')
        ):
            # Check if SAML session data is still valid
            if not request.session.get('saml_name_id'):
                logout(request)

        response = self.get_response(request)
        return response